  const py = `#!/usr/bin/env python3
"""Trend Sniper \u2014 pulls top YouTube videos for target keywords, asks a local
LLM (Ollama/LM Studio) to extract the algorithmic patterns, and writes a
planning report next to this script.

Shared keys (API key, OLLAMA_URL, MODEL) come from youtube_account.json so
you only set them once. Per-tool keys (TARGET_KEYWORDS) come from
trend_sniper.json. If a key exists in both, trend_sniper.json wins.

Requires:  pip install google-api-python-client requests
"""
import os, json, time, random, datetime, sys

HERE = os.path.dirname(os.path.abspath(__file__))
CONFIG_PATH = os.path.join(HERE, "trend_sniper.json")
ACCOUNT_PATH = os.path.join(HERE, "youtube_account.json")
REPORT_PATH = os.path.join(HERE, "trend_sniper_report.md")

def load_config():
    try:
        with open(CONFIG_PATH, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception as e:
        print(f"\u274C \uC124\uC815 \uD30C\uC77C\uC744 \uC77D\uC744 \uC218 \uC5C6\uC5B4\uC694: {CONFIG_PATH}\\n{e}")
        sys.exit(1)

def load_account():
    try:
        if os.path.exists(ACCOUNT_PATH):
            with open(ACCOUNT_PATH, "r", encoding="utf-8") as f:
                return json.load(f)
    except Exception:
        pass
    return {}

def _shared(cfg, acct, key, default=""):
    """Per-tool config wins; falls back to shared account; finally default."""
    v = cfg.get(key)
    if v not in (None, "", []):
        return v
    v = acct.get(key)
    if v not in (None, "", []):
        return v
    return default

def main():
    cfg = load_config()
    acct = load_account()
    api_key = (_shared(cfg, acct, "YOUTUBE_API_KEY") or "").strip()
    if not api_key:
        print("\u26A0\uFE0F  YOUTUBE_API_KEY\uAC00 \uBE44\uC5B4\uC788\uC5B4\uC694. youtube_account.json \uB610\uB294 trend_sniper.json\uC5D0 \uC785\uB825\uD558\uC138\uC694.")
        print("   \uBC1C\uAE09: https://console.cloud.google.com/ \u2192 YouTube Data API v3 \uC0AC\uC6A9 \uC124\uC815 \u2192 \uC0AC\uC6A9\uC790 \uC778\uC99D \uC815\uBCF4 \u2192 API \uD0A4")
        sys.exit(1)
    target_keywords = cfg.get("TARGET_KEYWORDS", [])
    if not target_keywords:
        print("\u26A0\uFE0F  TARGET_KEYWORDS\uAC00 \uBE44\uC5B4\uC788\uC5B4\uC694. \uBD84\uC11D\uD560 \uD0A4\uC6CC\uB4DC\uB97C 1\uAC1C \uC774\uC0C1 \uCD94\uAC00\uD558\uC138\uC694.")
        sys.exit(1)
    ollama_url = (_shared(cfg, acct, "OLLAMA_URL", "http://127.0.0.1:11434") or "http://127.0.0.1:11434").rstrip("/")
    model = _shared(cfg, acct, "MODEL", "") or ""
    pick = min(2, len(target_keywords))
    chosen = random.sample(target_keywords, pick)

    try:
        from googleapiclient.discovery import build
    except ImportError:
        print("\u274C google-api-python-client\uAC00 \uC124\uCE58\uB418\uC9C0 \uC54A\uC558\uC5B4\uC694.")
        print("   \uC124\uCE58: pip install google-api-python-client requests")
        sys.exit(1)
    try:
        import requests
    except ImportError:
        print("\u274C requests\uAC00 \uC124\uCE58\uB418\uC9C0 \uC54A\uC558\uC5B4\uC694. pip install requests")
        sys.exit(1)

    print(f"\\n\u{1F3AF} [\uD2B8\uB80C\uB4DC \uC2A4\uB098\uC774\uD37C] \uD0A4\uC6CC\uB4DC {chosen} \uC2A4\uCE94 \uC2DC\uC791...")
    youtube = build('youtube', 'v3', developerKey=api_key)
    last_month = (datetime.datetime.utcnow() - datetime.timedelta(days=30)).isoformat("T") + "Z"
    sniper_data = []
    for q in chosen:
        print(f"\u{1F4E1} [{q}] \uAC80\uC0C9 \uC911...")
        try:
            req = youtube.search().list(
                part="snippet", q=q, maxResults=5, order="viewCount",
                publishedAfter=last_month, type="video"
            )
            res = req.execute()
            for item in res.get('items', []):
                title = item['snippet']['title']
                channel = item['snippet']['channelTitle']
                sniper_data.append(f"[{q}] \uCC44\uB110: {channel} | \uC81C\uBAA9: {title}")
        except Exception as e:
            print(f"\u274C \uAC80\uC0C9 \uC624\uB958 ({q}): {e}")

    if not sniper_data:
        print("\u274C \uC218\uC9D1\uB41C \uB370\uC774\uD130 \uC5C6\uC74C. API \uD0A4 \uD55C\uB3C4/\uB124\uD2B8\uC6CC\uD06C \uD655\uC778.")
        sys.exit(1)

    data_text = "\\n".join(sniper_data)
    prompt = f"""\uB2F9\uC2E0\uC740 \uC720\uD29C\uBE0C \uC54C\uACE0\uB9AC\uC998 \uB9C8\uC2A4\uD130\uB9C8\uC778\uB4DC\uC785\uB2C8\uB2E4. \uC544\uB798\uB294 \uCD5C\uADFC 30\uC77C \uB5A1\uC0C1 \uC601\uC0C1\uC785\uB2C8\uB2E4.

[\uD0A4\uC6CC\uB4DC] {', '.join(chosen)}
[\uB370\uC774\uD130]
{data_text}

\uBD84\uC11D\uD574\uC11C \uB9C8\uD06C\uB2E4\uC6B4 \uBCF4\uACE0\uC11C\uB97C \uC791\uC131\uD558\uC138\uC694. \uBC18\uB4DC\uC2DC 3\uC139\uC158:
1. \u{1F30D} \uD2B8\uB80C\uB4DC \uD574\uD0B9 \uBD84\uC11D \u2014 \uC5B4\uB5A4 \uD328\uD134\uC774 \uC870\uD68C\uC218\uB97C \uB04C\uACE0 \uC788\uB294\uC9C0
2. \u{1F3AF} \uBE48\uC9D1 \uD138\uAE30 \uC804\uB7B5 \u2014 \uCC28\uBCC4\uD654 \uAC00\uB2A5\uD55C \uD2C8\uC0C8 \uC8FC\uC81C
3. \u{1F3AC} \uD30C\uAD34\uC801 \uC601\uC0C1 \uAE30\uD68D\uC548 \u2014 \uC378\uB124\uC77C \uCE74\uD53C, \uC81C\uBAA9 3\uAC1C, \uD6C4\uD0B9 \uC624\uD504\uB2DD(\uCCAB 5\uCD08)
"""

    print("\u{1F9E0} [LLM \uBD84\uC11D \uC911...]")
    if not model:
        # Try first available model
        try:
            r = requests.get(f"{ollama_url}/api/tags", timeout=5)
            r.raise_for_status()
            models = [m["name"] for m in r.json().get("models", [])]
            if not models:
                print("\u274C \uB85C\uCEEC LLM\uC5D0 \uC124\uCE58\uB41C \uBAA8\uB378\uC774 \uC5C6\uC5B4\uC694. Ollama/LM Studio\uC5D0\uC11C \uBAA8\uB378\uC744 \uD480(pull)\uD558\uC138\uC694.")
                sys.exit(1)
            model = models[0]
        except Exception as e:
            print(f"\u274C \uB85C\uCEEC LLM \uC5F0\uACB0 \uC2E4\uD328 ({ollama_url}): {e}")
            sys.exit(1)

    try:
        r = requests.post(
            f"{ollama_url}/api/generate",
            json={"model": model, "prompt": prompt, "stream": False},
            timeout=180,
        )
        r.raise_for_status()
        report = r.json().get("response", "").strip()
    except Exception as e:
        print(f"\u274C LLM \uD638\uCD9C \uC2E4\uD328: {e}")
        sys.exit(1)

    print("\\n" + "="*60)
    print(report)
    print("="*60)

    with open(REPORT_PATH, "a", encoding="utf-8") as f:
        now = time.strftime('%Y-%m-%d %H:%M:%S')
        f.write(f"\\n\\n# \u{1F3AF} \uD2B8\uB80C\uB4DC \uC2A4\uB098\uC774\uD551 \uBCF4\uACE0\uC11C \u2014 {now}\\n")
        f.write(f"## \u{1F4E1} \uD0A4\uC6CC\uB4DC: {', '.join(chosen)}\\n\\n")
        f.write(report)
        f.write("\\n\\n---\\n")
    print(f"\\n\u2705 \uBCF4\uACE0\uC11C \uC800\uC7A5: {REPORT_PATH}")

if __name__ == "__main__":
    main()
`;
