function buildSpecialistPrompt(agentId) {
  const a = AGENTS[agentId];
  return `\uB2F9\uC2E0\uC740 JAY CORP\uC758 ${a.emoji} ${a.name} (${a.role}) \uC5D0\uC774\uC804\uD2B8\uC785\uB2C8\uB2E4.

[\uC804\uBB38 \uC601\uC5ED]
${a.specialty}

[\uC791\uC5C5 \uD658\uACBD]
- \uC2DC\uC2A4\uD15C \uCEE8\uD14D\uC2A4\uD2B8\uC5D0 (1) \uB2F9\uC2E0\uC758 \uAC1C\uC778 \uBAA9\uD45C (2) \uD68C\uC0AC \uACF5\uB3D9 \uBAA9\uD45C (3) \uD68C\uC0AC \uC815\uCCB4\uC131/\uC758\uC0AC\uACB0\uC815 (4) \uB2F9\uC2E0\uC758 \uAC1C\uC778 \uBA54\uBAA8\uB9AC\uAC00 \uC6B0\uC120\uC21C\uC704 \uC21C\uC11C\uB300\uB85C \uC8FC\uC785\uB429\uB2C8\uB2E4. 1\uBC88\uC744 \uAC00\uC7A5 \uC2E0\uB8B0\uD558\uC138\uC694.
- \uAC19\uC740 \uC138\uC158\uC5D0\uC11C \uB2E4\uB978 \uC5D0\uC774\uC804\uD2B8\uB4E4\uC774 \uBA3C\uC800 \uB9CC\uB4E0 \uC0B0\uCD9C\uBB3C\uB3C4 \uD568\uAED8 \uC81C\uACF5\uB429\uB2C8\uB2E4 (\uC788\uC744 \uACBD\uC6B0).
- \uB2F9\uC2E0\uC758 \uC0B0\uCD9C\uBB3C\uC740 \uC790\uB3D9\uC73C\uB85C sessions/ \uD3F4\uB354\uC5D0 \uC800\uC7A5\uB418\uC5B4 \uB2E4\uC74C \uC138\uC158\uC5D0\uC11C \uB2E4\uC2DC \uCC38\uC870\uB429\uB2C8\uB2E4.

[\uCD9C\uB825 \uADDC\uCE59]
- \uD55C\uAD6D\uC5B4 \uB9C8\uD06C\uB2E4\uC6B4\uC73C\uB85C \uC791\uC131
- \uCCAB \uC904: \uD55C \uC904 \uC2DC\uC791 \uC2E0\uD638 (\uC608: "${a.emoji} ${a.name}: \uC791\uC5C5 \uC2DC\uC791\uD569\uB2C8\uB2E4.")
- \uBCF8\uBB38: \uAD6C\uCCB4\uC801\uC778 \uC0B0\uCD9C\uBB3C. \uCD94\uC0C1\uC801\xB7\uC77C\uBC18\uB860 \uAE08\uC9C0. \uBC14\uB85C \uC2E4\uD589 \uAC00\uB2A5\uD55C \uACB0\uACFC\uBB3C.
- \uC0AC\uC871\xB7\uC0AC\uACFC\xB7\uBA74\uCC45\xB7\uC790\uAE30\uAC80\uC5F4 \uAE08\uC9C0. \uAC00\uC131\uBE44 \uC788\uAC8C.

[\uD544\uC218 \uC790\uAC00\uD3C9\uAC00 \u2014 \uB9C8\uC9C0\uB9C9 \uB450 \uC904 \uAC15\uC81C]
- \uB05D\uC5D0\uC11C \uB450 \uBC88\uC9F8 \uC904: \`\u{1F4CA} \uD3C9\uAC00: <\uC644\uB8CC|\uC9C4\uD589\uC911|\uB300\uAE30> \u2014 <\uD55C \uBB38\uC7A5 \uC774\uC720>\`
  \xB7 \uC644\uB8CC = \uC774 \uC0B0\uCD9C\uBB3C\uB85C \uBAA9\uD45C\uAC00 \uB2EC\uC131\uB428
  \xB7 \uC9C4\uD589\uC911 = \uB2E4\uC74C \uC2A4\uD15D\uC5D0\uC11C \uB354 \uC9C4\uC804 \uAC00\uB2A5
  \xB7 \uB300\uAE30 = \uB2E4\uB978 \uC5D0\uC774\uC804\uD2B8/\uC0AC\uB78C\uC758 \uC785\uB825\uC774 \uD544\uC694\uD574 \uC9C0\uAE08\uC740 \uBA48\uCDA4
- \uB9C8\uC9C0\uB9C9 \uC904: \`\u{1F4DD} \uB2E4\uC74C \uB2E8\uACC4: <\uD55C \uC904, \uAD6C\uCCB4\uC801 \uC561\uC158>\` (\uB300\uAE30 \uC0C1\uD0DC\uBA74 "\uB300\uAE30 \u2014 <\uB204\uAD6C\uC758 \uBB34\uC5C7\uC774 \uD544\uC694>" \uD615\uC2DD)
- \uC790\uAC00\uD3C9\uAC00 \uC5C6\uC774 \uB05D\uB098\uBA74 \uC2DC\uC2A4\uD15C\uC774 \uC0B0\uCD9C\uBB3C\uC744 \uAC70\uBD80\uD569\uB2C8\uB2E4.`;
}
async function _safeGitAutoSync(brainDir, commitMsg, provider = null) {
  if (_autoSyncRunning) return;
  _autoSyncRunning = true;
  const notify = (msg, delayMs = 4e3) => {
    if (provider && provider.injectSystemMessage) {
      setTimeout(() => provider.injectSystemMessage(msg), delayMs);
    }
  };
  try {
    if (!isGitAvailable()) {
      notify(`\u26A0\uFE0F **[GitHub Sync \uAC74\uB108\uB700]** git\uC774 \uC124\uCE58\uB418\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4. https://git-scm.com \uC5D0\uC11C \uC124\uCE58 \uD6C4 \uC7AC\uC2DC\uB3C4\uD558\uC138\uC694. (\uB85C\uCEEC \uD30C\uC77C\uC740 \uC548\uC804\uD558\uAC8C \uC800\uC7A5\uB428)`);
      return;
    }
    const isRepo = gitExecSafe(["status"], brainDir) !== null;
    if (!isRepo) {
      const repoUrl = vscode.workspace.getConfiguration("connectAiLab").get("secondBrainRepo", "");
      const cleanRepo = repoUrl ? validateGitRemoteUrl(repoUrl) : null;
      if (!cleanRepo) {
        notify(`\u2705 \uC9C0\uC2DD\uC774 \uB85C\uCEEC\uC5D0 \uC800\uC7A5\uB418\uC5C8\uC2B5\uB2C8\uB2E4.

\u{1F4A1} **Tip:** \uAE43\uD5C8\uBE0C \uBC31\uC5C5\uC744 \uC6D0\uD558\uC2DC\uBA74 \u{1F9E0} \uBA54\uB274 \u2192 '\uAE43\uD5C8\uBE0C \uB3D9\uAE30\uD654'\uB97C \uB20C\uB7EC \uC800\uC7A5\uC18C\uB97C \uC5F0\uACB0\uD558\uC138\uC694!`, 3e3);
        return;
      }
      const initRes = gitRun(["init"], brainDir, 1e4);
      if (initRes.status !== 0) {
        notify(`\u26A0\uFE0F **[GitHub Sync]** git init \uC2E4\uD328: ${classifyGitError(initRes.stderr).message}`);
        return;
      }
    }
    ensureBrainGitignore(brainDir);
    ensureInitialCommit(brainDir);
    gitExecSafe(["add", "."], brainDir);
    gitExecSafe(["commit", "-m", commitMsg], brainDir);
    const existingRemote = gitExecSafe(["remote", "get-url", "origin"], brainDir)?.trim() || "";
    if (!existingRemote) {
      const repoUrl = vscode.workspace.getConfiguration("connectAiLab").get("secondBrainRepo", "");
      const cleanRepo = repoUrl ? validateGitRemoteUrl(repoUrl) : null;
      if (!cleanRepo) {
        notify(`\u2705 \uC9C0\uC2DD\uC774 \uB85C\uCEEC\uC5D0 \uC548\uC804\uD558\uAC8C \uC800\uC7A5\uB418\uC5C8\uC2B5\uB2C8\uB2E4.

\u{1F4A1} **Tip:** \uAE43\uD5C8\uBE0C \uBC31\uC5C5\uC744 \uC6D0\uD558\uC2DC\uBA74 \u{1F9E0} \uBA54\uB274 \u2192 '\uAE43\uD5C8\uBE0C \uB3D9\uAE30\uD654'\uB97C \uB20C\uB7EC\uC8FC\uC138\uC694!`, 3e3);
        return;
      }
      gitExecSafe(["remote", "add", "origin", cleanRepo], brainDir);
    }
    const remoteBranch = getRemoteDefaultBranch(brainDir);
    const currentBranch = gitExecSafe(["rev-parse", "--abbrev-ref", "HEAD"], brainDir)?.trim() || "";
    if (currentBranch && currentBranch !== remoteBranch) {
      gitExecSafe(["branch", "-M", remoteBranch], brainDir);
    }
    const fetchRes = gitRun(["fetch", "origin", remoteBranch], brainDir, 3e4);
    if (fetchRes.status !== 0) {
      const err = classifyGitError(fetchRes.stderr);
      notify(`\u26A0\uFE0F **[GitHub Sync \uC2E4\uD328]** ${err.message}`);
      return;
    }
    const ffRes = gitRun(["merge", "--ff-only", `origin/${remoteBranch}`], brainDir, 15e3);
    if (ffRes.status !== 0) {
      const stderrLower = ffRes.stderr.toLowerCase();
      const diverged = stderrLower.includes("not possible") || stderrLower.includes("non-fast-forward") || stderrLower.includes("refusing");
      if (diverged) {
        notify(`\u{1F4A1} **\uC628\uB77C\uC778 \uC9C0\uC2DD\uACFC \uB85C\uCEEC\uC5D0 \uC11C\uB85C \uB2E4\uB978 \uB0B4\uC6A9\uC774 \uC788\uC5B4\uC694.** \uB3D9\uAE30\uD654\uD558\uB824\uBA74 \uCC44\uD305\uCC3D \uC704 \uC54C\uB9BC\uC758 "\uBCD1\uD569\uD558\uAE30"\uB97C \uB204\uB974\uAC70\uB098 \uBA54\uB274 \u2192 \u{1F9E0} \u2192 '\uAE43\uD5C8\uBE0C \uB3D9\uAE30\uD654'\uB97C \uB20C\uB7EC\uC8FC\uC138\uC694. (\uB85C\uCEEC \uD30C\uC77C\uC740 \uC548\uC804\uD569\uB2C8\uB2E4)`);
        vscode.window.showWarningMessage(
          "\uC628\uB77C\uC778 \uC9C0\uC2DD(GitHub)\uACFC \uB85C\uCEEC\uC5D0 \uC11C\uB85C \uB2E4\uB978 \uBCC0\uACBD\uC0AC\uD56D\uC774 \uC788\uC2B5\uB2C8\uB2E4. \uB3D9\uAE30\uD654\uD558\uC2DC\uACA0\uC5B4\uC694?",
          "\uBCD1\uD569\uD558\uAE30",
          "\uB098\uC911\uC5D0"
        ).then((choice) => {
          if (choice === "\uBCD1\uD569\uD558\uAE30" && provider && provider._syncSecondBrain) {
            provider._syncSecondBrain().catch(() => {
            });
          }
        });
        return;
      }
    }
    const pushRes = gitRun(["push", "-u", "origin", remoteBranch], brainDir, 6e4);
    if (pushRes.status === 0) {
      notify(`\u2705 **[GitHub Sync]** \uAE00\uB85C\uBC8C \uB1CC(Second Brain)\uC5D0 \uC9C0\uC2DD\uC774 \uC790\uB3D9 \uBC31\uC5C5\uB418\uC5C8\uC2B5\uB2C8\uB2E4!`, 5e3);
    } else {
      const err = classifyGitError(pushRes.stderr);
      notify(`\u26A0\uFE0F **[GitHub Sync \uC2E4\uD328]** ${err.message}

\u{1F4A1} \uBA54\uB274 \u2192 \u{1F9E0} \u2192 '\uAE43\uD5C8\uBE0C \uB3D9\uAE30\uD654' \uC5D0\uC11C \uC218\uB3D9 \uD574\uACB0\uC744 \uC2DC\uB3C4\uD574\uBCF4\uC138\uC694. (\uB85C\uCEEC \uD30C\uC77C\uC740 \uC548\uC804\uD569\uB2C8\uB2E4)`);
    }
  } catch (e) {
    console.error("Git Auto-Sync Failed:", e);
    notify(`\u26A0\uFE0F **[GitHub Sync \uC624\uB958]** ${e?.message || e}
(\uB85C\uCEEC \uD30C\uC77C\uC740 \uC548\uC804\uD569\uB2C8\uB2E4)`);
  } finally {
    _autoSyncRunning = false;
  }
}
var _activeChatProvider = null;
var _extCtx = null;
function _recoverEngineUrlIfMismatched(context) {
  if (context.globalState.get("engineUrlRecovered")) return;
  (async () => {
    try {
      const cfg = vscode.workspace.getConfiguration("connectAiLab");
      const url2 = (cfg.get("ollamaUrl") || "").trim();
      const model = (cfg.get("defaultModel") || "").trim();
      if (!model) {
        await context.globalState.update("engineUrlRecovered", true);
        return;
      }
      const looksLMStudio = /\//.test(model) || /gguf/i.test(model);
      const urlIsOllama = !url2 || url2.includes("11434");
      const urlIsLM = url2.includes("1234") || url2.includes("/v1");
      const mismatched = looksLMStudio && urlIsOllama || !looksLMStudio && urlIsLM;
      if (!mismatched) {
        await context.globalState.update("engineUrlRecovered", true);
        return;
      }
      const probe = async (base, isLM) => {
        try {
          if (isLM) {
            const r2 = await axios_default.get(`${base}/v1/models`, { timeout: 1500 });
            return Array.isArray(r2.data?.data) && r2.data.data.some((m) => m.id === model);
          }
          const r = await axios_default.get(`${base}/api/tags`, { timeout: 1500 });
          return Array.isArray(r.data?.models) && r.data.models.some((m) => m.name === model);
        } catch {
          return false;
        }
      };
      let target = "";
      if (await probe("http://127.0.0.1:1234", true)) target = "http://127.0.0.1:1234";
      else if (await probe("http://127.0.0.1:11434", false)) target = "http://127.0.0.1:11434";
      if (target && target !== url2) {
        await cfg.update("ollamaUrl", target, vscode.ConfigurationTarget.Global);
        console.log(`Connect AI: engine URL recovered \u2192 ${target} (model: ${model})`);
      }
      await context.globalState.update("engineUrlRecovered", true);
    } catch (e) {
      console.error("Connect AI: engine URL recovery failed", e);
    }
  })();
}
function _autoPickInstalledModelIfMissing() {
  (async () => {
    try {
      const cfg = vscode.workspace.getConfiguration("connectAiLab");
      const current = (cfg.get("defaultModel") || "").trim();
      if (current) return;
      const url2 = (cfg.get("ollamaUrl") || "http://127.0.0.1:11434").trim();
      const isLM = url2.includes("1234") || url2.includes("/v1");
      if (isLM) {
        try {
          const r = await axios_default.get(`${url2}/v1/models`, { timeout: 1500 });
          const models = r.data?.data || [];
          if (models.length > 0) {
            await cfg.update("defaultModel", models[0].id, vscode.ConfigurationTarget.Global);
            console.log(`Connect AI: auto-picked LM Studio model \u2192 ${models[0].id}`);
          }
        } catch {
        }
      } else {
        try {
          const r = await axios_default.get(`${url2}/api/tags`, { timeout: 1500 });
          const models = r.data?.models || [];
          if (models.length > 0) {
            models.sort((a, b) => (a.size || 0) - (b.size || 0));
            await cfg.update("defaultModel", models[0].name, vscode.ConfigurationTarget.Global);
            console.log(`Connect AI: auto-picked Ollama model \u2192 ${models[0].name} (${(models[0].size / 1e9).toFixed(2)} GB)`);
          }
        } catch {
        }
      }
    } catch (e) {
      console.error("Connect AI: auto-pick model failed", e);
    }
  })();
}
