    const folderPath = _isBrainDirExplicitlySet() ? _getBrainDir() : "";
    let fileCount = 0;
    if (folderPath && fs.existsSync(folderPath)) {
      try {
        fileCount = this._findBrainFiles(folderPath).length;
      } catch {
      }
    }
    const githubUrl = cfg.get("secondBrainRepo", "") || "";
