const vscode=acquireVsCodeApi(),chat=document.getElementById('chat'),input=document.getElementById('input'),
sendBtn=document.getElementById('sendBtn'),stopBtn=document.getElementById('stopBtn'),
modelSel=document.getElementById('modelSel'),newChatBtn=document.getElementById('newChatBtn'),settingsBtn=document.getElementById('settingsBtn'),brainBtn=document.getElementById('brainBtn'),thinkingBtn=document.getElementById('thinkingBtn'),
internetBtn=document.getElementById('internetBtn'),attachBtn=document.getElementById('attachBtn'),injectLocalBtn=document.getElementById('injectLocalBtn'),fileInput=document.getElementById('fileInput'),attachPreview=document.getElementById('attachPreview'),
thinkingBar=document.getElementById('thinkingBar'),corporateBtn=document.getElementById('corporateBtn'),agentBoard=document.getElementById('agentBoard'),abGrid=document.getElementById('abGrid'),abSvg=document.getElementById('abSvg'),abFolder=document.getElementById('abFolder'),abCompanyName=document.getElementById('abCompanyName'),abFolderText=document.getElementById('abFolderText'),brandSuffix=document.getElementById('brandSuffix');
let loader=null,sending=false,pendingFiles=[],internetEnabled=false,corporateMode=false,officeOpen=false,corporateUnlocked=false;
/* Smart auto-scroll: only stick to the bottom if the user is already near it.
   If they scrolled up to read earlier messages, leave their view alone. */
function scrollChatToBottomIfNear(){
  if (!chat) return;
  const nearBottom = (chat.scrollHeight - chat.scrollTop - chat.clientHeight) < 120;
  if (nearBottom) chat.scrollTo({ top: chat.scrollHeight });
}
let agentMap={},agentCardEls={},agentStreamEls={};
let companyState={configured:false,name:'',dir:'',folderExists:false,brainExplicitlySet:false};
let _setupCompletionAnnounced=false;
function welcomeHtml(){
  return '<div class="welcome"><div class="welcome-logo">\u2726</div>'
    + '<div class="ag-badge">\u26A1 Built for Antigravity</div>'
    + '<div class="welcome-title">AI 1\uC778 \uAE30\uC5C5, \uC2DC\uC791\uD558\uC138\uC694</div>'
    + '<div class="welcome-sub">\uB098\uB9CC\uC758 AI \uC5D0\uC774\uC804\uD2B8 \uD300\uACFC \uC81C2\uC758 \uB450\uB1CC\uAC00 \uD55C \uACF3\uC5D0\uC11C.<br>100% \uB85C\uCEEC\xB7\uC624\uD504\uB77C\uC778\xB7\uBB34\uB8CC \u2014 \uC778\uD130\uB137\uB3C4 API \uBE44\uC6A9\uB3C4 \uC5C6\uC774 \uB0B4 PC\uC5D0\uC11C.</div>'
    + '<div id="onboardRoot"></div>'
    + '</div>';
}

let onboardingCardShown = false;
let onboardingStep = 1;
let onboardingState = null;

function renderOnboarding(){
  const root = document.getElementById('onboardRoot');
  if (!root || !onboardingState || onboardingState.dismissed) return;
  const s = onboardingState.steps;
  const totalDone = (s.engine.done?1:0) + (s.brain.done?1:0) + (s.github.done?1:0);
  /* Determine current step: first not-done, capped at 4 (success state) */
  let cur = onboardingStep;
  if (cur === 1 && s.engine.done) cur = 2;
  if (cur === 2 && s.brain.done) cur = 3;
  if (cur === 3 && (s.github.done || onboardingState.githubSkipped)) cur = 4;
  onboardingStep = cur;
  const dot = (n) => '<div class="onboard-dot '+(n<cur?'done':n===cur?'active':'')+'"></div>';
  let stepHtml = '';
  if (cur === 1) {
    const detected = s.engine.detected;
    stepHtml =
      '<div class="onboard-step-label">STEP 1 OF 4 \xB7 AI \uC5D4\uC9C4</div>'
    + '<div class="onboard-step-title">\u{1F916} AI \uC5D4\uC9C4 \uC5F0\uACB0</div>'
    + '<div class="onboard-step-body">'
    +   '<strong>Ollama</strong>(<code>ollama.com</code>)\uC640 <strong>LM Studio</strong>(<code>lmstudio.ai</code>) \u2014 '
    +   '<u>\uB458 \uB2E4 \uAE54\uC544\uBCF4\uACE0 \uB0B4 PC\uC5D0\uC11C \uB354 \uBE60\uB974\uAC8C \uB3C4\uB294 \uCABD\uC744 \uC120\uD0DD\uD558\uC138\uC694</u>. '
    +   '\uAC19\uC740 \uBAA8\uB378\uB3C4 \uC2DC\uC2A4\uD15C\xB7\uB4DC\uB77C\uC774\uBC84\uC5D0 \uB530\uB77C \uC18D\uB3C4\uAC00 \uD06C\uAC8C \uB2E4\uB985\uB2C8\uB2E4.<br>'
    +   '<br>\uBAA8\uB378 \uD558\uB098 \uB85C\uB4DC\uD574\uB450\uACE0 \uC544\uB798 \uBC84\uD2BC \uB204\uB974\uBA74 \uC790\uB3D9 \uAC10\uC9C0\uB429\uB2C8\uB2E4.'
    +   (detected ? '<div class="onboard-result">\u2705 \uAC10\uC9C0\uB428: '+escapeHtml(detected)+(s.engine.model?' \xB7 '+escapeHtml(s.engine.model):'')+'</div>' : '')
    + '</div>'
    + '<div class="onboard-actions">'
    +   '<button class="onboard-btn" id="ob-detect">\u{1F50D} \uC790\uB3D9 \uAC10\uC9C0</button>'
    +   '<button class="onboard-btn secondary" id="ob-skip-engine">\uAC74\uB108\uB6F0\uAE30</button>'
    + '</div>';
  } else if (cur === 2) {
    stepHtml =
      '<div class="onboard-step-label">STEP 2 OF 4 \xB7 \uB450\uB1CC \uD3F4\uB354</div>'
    + '<div class="onboard-step-title">\u{1F9E0} \uB0B4 \uC9C0\uC2DD\uC774 \uC0B4 \uACF3\uC744 \uC815\uD574\uC8FC\uC138\uC694</div>'
    + '<div class="onboard-step-body">'
    +   '\uC5EC\uAE30\uC5D0 \uBAA8\uB4E0 \uAC8C \uBAA8\uC785\uB2C8\uB2E4:<br>'
    +   '\u2022 \uB9C8\uD06C\uB2E4\uC6B4 \uC9C0\uC2DD (.md)<br>'
    +   '\u2022 \uD68C\uC0AC \uD3F4\uB354 (\uC5D0\uC774\uC804\uD2B8 \uBA54\uBAA8\uB9AC\xB7\uC815\uCCB4\uC131)<br>'
    +   '\u2022 \uB300\uD654 \uB85C\uADF8 (\uB0A0\uC9DC\uBCC4 \uB204\uC801)<br>'
    +   '<br>\u{1F449} <strong>\uD68C\uC0AC \uD3F4\uB354\uC640 \uAC19\uC740 \uC704\uCE58</strong>\uB85C \uC790\uB3D9 \uD1B5\uD569\uB418\uB2C8 \uD55C \uBC88\uB9CC \uC815\uD558\uBA74 \uB05D.'
    +   (s.brain.path ? '<div class="onboard-result">\u{1F4C1} \uD604\uC7AC: <code>'+escapeHtml(s.brain.path)+'</code></div>' : '')
    + '</div>'
    + '<div class="onboard-actions">'
    +   '<button class="onboard-btn" id="ob-pick-brain">\u{1F4C1} \uD3F4\uB354 \uC120\uD0DD</button>'
    +   '<button class="onboard-btn secondary" id="ob-skip-brain">\uAE30\uBCF8\uAC12 \uC0AC\uC6A9</button>'
    + '</div>';
  } else if (cur === 3) {
    stepHtml =
      '<div class="onboard-step-label">STEP 3 OF 4 \xB7 GitHub \uB3D9\uAE30\uD654 (\uC120\uD0DD)</div>'
    + '<div class="onboard-step-title">\u2601\uFE0F \uC9C0\uC2DD\uC744 \uAE43\uD5C8\uBE0C\uC5D0 \uBC31\uC5C5\uD560\uAE4C\uC694?</div>'
    + '<div class="onboard-step-body">'
    +   '\uB450\uB1CC \uD3F4\uB354\uAC00 \uC790\uB3D9\uC73C\uB85C git push \uB429\uB2C8\uB2E4 \u2014 PC\uAC00 \uB9DD\uAC00\uC838\uB3C4 \uC548\uC804.<br>'
    +   '\uB2E4\uB978 \uB514\uBC14\uC774\uC2A4\uC5D0\uC11C\uB3C4 \uAC19\uC740 \uC9C0\uC2DD\xB7\uD68C\uC0AC \uC0C1\uD0DC \uC0AC\uC6A9 \uAC00\uB2A5.<br>'
    +   '<br>\uB098\uC911\uC5D0 \uC124\uC815\uD574\uB3C4 \uB429\uB2C8\uB2E4.'
    +   (s.github.url ? '<div class="onboard-result">\u{1F517} \uC5F0\uACB0\uB428: <code>'+escapeHtml(s.github.url)+'</code></div>' : '')
    + '</div>'
    + '<input class="onboard-input" id="ob-repo-url" placeholder="https://github.com/\uC0AC\uC6A9\uC790/my-brain.git" value="'+(s.github.url||'')+'" />'
    + '<div id="ob-repo-result"></div>'
    + '<div class="onboard-actions" style="margin-top:8px">'
    +   '<button class="onboard-btn" id="ob-save-repo">\u{1F4BE} \uC800\uC7A5</button>'
    +   '<button class="onboard-btn secondary" id="ob-skip-github">\uAC74\uB108\uB6F0\uAE30</button>'
    + '</div>';
  } else { /* cur === 4: success */
    stepHtml =
      '<div class="onboard-step-label">\uC644\uB8CC \u2728</div>'
    + '<div class="onboard-step-title">\u{1F389} \uC14B\uC5C5 \uB05D! \uB358\uC838\uB9CC \uC8FC\uC138\uC694</div>'
    + '<div class="onboard-step-body">'
    +   '\uD55C \uC904 \uBA85\uB839\uC73C\uB85C \uC2DC\uC791:<br>'
    +   '\u2022 <code>\uC774 \uCF54\uB4DC \uC124\uBA85\uD574\uC918</code><br>'
    +   '\u2022 <code>\uC720\uD29C\uBE0C \uC601\uC0C1 5\uAC1C \uAE30\uD68D (\u{1F454} \uAE30\uC5C5 \uBAA8\uB4DC)</code><br>'
    +   '\u2022 <code>\uC624\uB298 \uC77C\uACFC \uD154\uB808\uADF8\uB7A8\uC73C\uB85C \uBCF4\uACE0 (\u{1F454} \uAE30\uC5C5 \uBAA8\uB4DC)</code>'
    + '</div>'
    + '<div class="onboard-actions">'
    +   '<button class="onboard-btn" id="ob-finish">\uC2DC\uC791\uD558\uAE30 \u2726</button>'
    + '</div>';
  }
  root.innerHTML =
      '<div class="onboard-card">'
    +   '<div class="onboard-head">'
    +     '<div class="onboard-title">\u{1F680} 1\uBD84 \uC14B\uC5C5</div>'
    +     '<button class="onboard-skip" id="ob-dismiss">\u2715 \uB098\uC911\uC5D0</button>'
    +   '</div>'
    +   '<div class="onboard-progress">'+dot(1)+dot(2)+dot(3)+dot(4)+'</div>'
    +   stepHtml
    + '</div>';
  /* Wire button events */
  const wire = (id, fn) => { const el = document.getElementById(id); if (el) el.addEventListener('click', fn); };
  wire('ob-detect', () => vscode.postMessage({ type: 'detectEngine' }));
  wire('ob-skip-engine', () => { onboardingStep = 2; renderOnboarding(); });
  wire('ob-pick-brain', () => vscode.postMessage({ type: 'pickBrainFolder' }));
  wire('ob-skip-brain', () => { onboardingStep = 3; renderOnboarding(); });
  wire('ob-save-repo', () => {
    const inp = document.getElementById('ob-repo-url');
    vscode.postMessage({ type: 'setSecondBrainRepo', value: inp ? inp.value : '' });
  });
  wire('ob-skip-github', () => { if (onboardingState) onboardingState.githubSkipped = true; onboardingStep = 4; renderOnboarding(); });
  wire('ob-finish', () => {
    vscode.postMessage({ type: 'dismissOnboarding' });
    if (onboardingState) onboardingState.dismissed = true;
    const root2 = document.getElementById('onboardRoot');
    if (root2) root2.innerHTML = '';
  });
  wire('ob-dismiss', () => {
    vscode.postMessage({ type: 'dismissOnboarding' });
    if (onboardingState) onboardingState.dismissed = true;
    const root2 = document.getElementById('onboardRoot');
    if (root2) root2.innerHTML = '';
  });
}

